#define WIDTH 16
#define HEIGHT 16
#define BLOCK_SIZE 16

float squash(float x) {
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* l1,
                                  global float* l2,
                                  global float* conn_flat,
                                  global float* partial_sum,
                                  local float* local_conn,
                                  local float* local_l1,
                                  int n1,
                                  int n2) {
    int j = get_global_id(1);
    int block_idx = get_global_id(0) / BLOCK_SIZE;
    int local_idx = get_global_id(0) % BLOCK_SIZE;

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        int start_k = block_idx * BLOCK_SIZE;
        int end_k = start_k + BLOCK_SIZE;
        if (end_k > n1 + 1) end_k = n1 + 1;

        for (int k = start_k; k < end_k; k++) {
            if (k <= n1) {
                float weight = conn_flat[k * (n2 + 1) + j];
                float input_val = l1[k];
                sum += weight * input_val;
            }
        }

        partial_sum[block_idx * n2 + (j - 1)] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(global float* delta,
                                    int ndelta,
                                    global float* ly,
                                    int nly,
                                    global float* w_flat,
                                    global float* oldw_flat) {
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float d = delta[j];
        float l = ly[k];
        float old_dw = oldw_flat[k * (ndelta + 1) + j];

        float new_dw = (0.3f * d * l) + (0.3f * old_dw);

        w_flat[k * (ndelta + 1) + j] += new_dw;
        oldw_flat[k * (ndelta + 1) + j] = new_dw;
    }
}
